// --- CONFIGURATION ---
// IMPORTANT: Add the Google email addresses of users who are allowed to edit the sheet.
const AUTHORIZED_USERS = ['techcelljedslkzj@gmail.com', 'techcelldlskzj@gmail.com', 'brt1179fl@gmail.com']; 
const SHEET_NAME = '22-23 Traction Failures'; // The name of the sheet to edit.

// --- DO NOT EDIT BELOW THIS LINE ---

function doPost(e) {
  try {
    const payload = JSON.parse(e.postData.contents);
    const { locoNo, dateFailed, newCauseOfFailure, idToken } = payload;

    if (!idToken) {
      return createJsonResponse({ status: 'error', message: 'Missing authentication token.' }, 401);
    }
    if (!locoNo || !dateFailed || newCauseOfFailure === undefined) {
      return createJsonResponse({ status: 'error', message: 'Missing required data fields.' }, 400);
    }

    // 1. Authenticate the user
    const userEmail = validateTokenAndGetUserEmail(idToken);
    if (!userEmail) {
      return createJsonResponse({ status: 'error', message: 'Invalid or expired token.' }, 401);
    }

    // 2. Authorize the user
    if (AUTHORIZED_USERS.indexOf(userEmail) === -1) {
      return createJsonResponse({ status: 'error', message: 'User is not authorized to perform this action.' }, 403);
    }

    // 3. Update the Sheet
    const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_NAME);
    if (!sheet) {
      return createJsonResponse({ status: 'error', message: `Sheet named '${SHEET_NAME}' not found.` }, 500);
    }

    // --- FIX STARTS HERE ---
    // We need both the raw values (for numbers) and the displayed, formatted values (for dates).
    const dataRange = sheet.getDataRange();
    const values = dataRange.getValues(); // Use for raw data like Loco No.
    const displayValues = dataRange.getDisplayValues(); // Use for formatted data like dates.
    // --- FIX ENDS HERE ---

    const headers = values[0].map(h => h.toLowerCase().replace(/\s/g, '').replace(/[^a-z0-9]/gi, ''));

    const locoNoCol = headers.indexOf('locono');
    const dateFailedCol = headers.indexOf('datefailed');
    const causeCol = headers.indexOf('causeoffailure');

    if (locoNoCol === -1 || dateFailedCol === -1 || causeCol === -1) {
      return createJsonResponse({ status: 'error', message: 'Could not find required columns in the sheet.' }, 500);
    }

    // --- FIX STARTS HERE ---
    // Loop through the rows and compare the correct value types.
    for (let i = 1; i < values.length; i++) {
      // Compare Loco No from `values` (raw data)
      // Compare Date Failed from `displayValues` (the formatted string, e.g., "17-10-25")
      if (values[i][locoNoCol] == locoNo && displayValues[i][dateFailedCol] == dateFailed) {
        sheet.getRange(i + 1, causeCol + 1).setValue(newCauseOfFailure);
        return createJsonResponse({ status: 'success', message: `Row ${i+1} updated successfully.` });
      }
    }
    // --- FIX ENDS HERE ---

    return createJsonResponse({ status: 'error', message: 'Matching record not found.' }, 404);

  } catch (error) {
    return createJsonResponse({ status: 'error', message: 'An internal server error occurred: ' + error.message }, 500);
  }
}

function validateTokenAndGetUserEmail(idToken) {
  try {
    const response = UrlFetchApp.fetch(`https://oauth2.googleapis.com/tokeninfo?id_token=${idToken}`);
    const payload = JSON.parse(response.getContentText());

    // You can add more checks here, like `payload.aud` to match your Client ID.
    if (payload.email && payload.email_verified) {
      return payload.email;
    }
    return null;
  } catch (e) {
    return null;
  }
}

function createJsonResponse(data, statusCode = 200) {
  const output = ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
  // While Apps Script doesn't truly support status codes, this is good practice for logs.
  return output;
}


